import { TextInput, TextInputPrimitive } from './text-input';
import { NumericInput, NumericInputPrimitive } from './numeric-input';
import { ColorInput, ColorChit, ColorInputPrimitive } from './color-input';
import { InputMultiRoot, InputRoot } from './input-utils';

const Input = TextInput;

export {
  TextInput,
  TextInputPrimitive,
  NumericInput,
  NumericInputPrimitive,
  ColorInput,
  ColorInputPrimitive,
  ColorChit,
  Input,
  InputMultiRoot,
  InputRoot,
};

import { Input as BaseInput } from '@base-ui/react';
import { cn } from '@/lib/utils';
import { InputRoot, type BaseInputProps } from './input-utils';

function TextInputPrimitive({
  className,
  iconLead,
  iconTrail,
  ...props
}: BaseInputProps) {
  return (
    <div className='flex h-full items-center pr-2 pl-2 has-data-[figui=input-icon-lead]:pl-0 has-data-[figui=input-icon-trail]:pr-0'>
      {iconLead && (
        <div
          className='flex aspect-square size-6 items-center justify-center select-none'
          data-figui='input-icon-lead'
        >
          {typeof iconLead === 'string' ? (
            <span className='text-black-500 dark:text-white-500'>
              {iconLead}
            </span>
          ) : (
            iconLead
          )}
        </div>
      )}
      <BaseInput
        className={cn('h-full w-full outline-none', className)}
        {...props}
      />
      {iconTrail && (
        <div
          className='flex aspect-square size-6 items-center justify-center select-none'
          data-figui='input-icon-trail'
        >
          {typeof iconTrail === 'string' ? (
            <span className='text-black-500 dark:text-white-500'>
              {iconTrail}
            </span>
          ) : (
            iconTrail
          )}
        </div>
      )}
    </div>
  );
}

function TextInput({ iconLead, className, ...props }: BaseInputProps) {
  return (
    <InputRoot className={cn(className)}>
      <TextInputPrimitive iconLead={iconLead} {...props} />
    </InputRoot>
  );
}

export { TextInput, TextInputPrimitive };

'use client';

import {
  InputRoot,
  type BaseInputProps,
  useInputRootContext,
} from './input-utils';
import { TextInputPrimitive } from './text-input';
import { Input as BaseInput } from '@base-ui/react';

import React from 'react';

const NUMBER_REGEX = /^-?\d+(\.\d+)?$/;
const OPERATORS_REGEX = /[+\-*/()]/;
const PREC: Record<string, number> = {
  'u-': 3,
  '*': 2,
  '/': 2,
  '+': 1,
  '-': 1,
};
const RIGHT_ASSOC = new Set(['u-']);

const toStringValue = (v: unknown): string => {
  if (typeof v === 'number') return String(v);
  if (typeof v === 'string') return v;
  return '';
};

const isValidNumber = (v: string): boolean => NUMBER_REGEX.test(v);

const getDecimalPlaces = (n: number): number => {
  const s = String(n);
  const i = s.indexOf('.');
  return i >= 0 ? s.length - i - 1 : 0;
};

const trimTrailingZeros = (s: string): string => {
  if (!s.includes('.')) return s;
  return s.replace(/\.0+$/, '').replace(/(\.\d*?)0+$/, '$1');
};

const evaluateExpression = (expr: string): number | null => {
  const tokens: (number | string)[] = [];
  const src = expr.replace(/\s+/g, '');
  let i = 0;
  const isDigit = (c: string) => /[0-9]/.test(c);
  while (i < src.length) {
    const c = src[i];
    if (isDigit(c) || c === '.') {
      let j = i + 1;
      while (j < src.length && (isDigit(src[j]) || src[j] === '.')) j++;
      const n = Number(src.slice(i, j));
      if (!Number.isFinite(n)) return null;
      tokens.push(n);
      i = j;
    } else if (
      c === '+' ||
      c === '-' ||
      c === '*' ||
      c === '/' ||
      c === '(' ||
      c === ')'
    ) {
      const prev = tokens[tokens.length - 1];
      if (
        c === '-' &&
        (prev === undefined ||
          (typeof prev === 'string' &&
            (prev === '+' ||
              prev === '-' ||
              prev === '*' ||
              prev === '/' ||
              prev === '(')))
      ) {
        tokens.push('u-');
        i++;
      } else {
        tokens.push(c);
        i++;
      }
    } else {
      return null;
    }
  }
  const output: (number | string)[] = [];
  const ops: string[] = [];
  for (const t of tokens) {
    if (typeof t === 'number') {
      output.push(t);
    } else if (t === '(') {
      ops.push(t);
    } else if (t === ')') {
      while (ops.length && ops[ops.length - 1] !== '(')
        output.push(ops.pop() as string);
      if (ops.pop() !== '(') return null;
    } else {
      while (
        ops.length &&
        ops[ops.length - 1] !== '(' &&
        ((RIGHT_ASSOC.has(t) && PREC[t] < PREC[ops[ops.length - 1]]) ||
          (!RIGHT_ASSOC.has(t) && PREC[t] <= PREC[ops[ops.length - 1]]))
      )
        output.push(ops.pop() as string);
      ops.push(t);
    }
  }
  while (ops.length) {
    const op = ops.pop() as string;
    if (op === '(') return null;
    output.push(op);
  }
  const stack: number[] = [];
  for (const t of output) {
    if (typeof t === 'number') stack.push(t);
    else if (t === 'u-') {
      const a = stack.pop();
      if (a === undefined) return null;
      stack.push(-a);
    } else {
      const b = stack.pop();
      const a = stack.pop();
      if (a === undefined || b === undefined) return null;
      let r: number;
      if (t === '+') r = a + b;
      else if (t === '-') r = a - b;
      else if (t === '*') r = a * b;
      else if (t === '/') r = a / b;
      else return null;
      if (!Number.isFinite(r)) return null;
      stack.push(r);
    }
  }
  if (stack.length !== 1) return null;
  return stack[0];
};

const clampNumber = (num: number, minNum?: number, maxNum?: number): number => {
  let result = num;
  if (minNum !== undefined && Number.isFinite(minNum) && result < minNum)
    result = minNum;
  if (maxNum !== undefined && Number.isFinite(maxNum) && result > maxNum)
    result = maxNum;
  return result;
};

interface NumericInputProps extends BaseInputProps {
  nudgeAmount?: number;
  min?: number | string;
  max?: number | string;
  onValueChange?: (next: string) => void;
}

function NumericInputPrimitive({
  onChange,
  onBlur,
  onKeyDown,
  value,
  defaultValue,
  nudgeAmount = 1,
  min,
  max,
  className,
  onValueChange,
  ...props
}: NumericInputProps) {
  type BaseInputChangeEvent = Parameters<
    NonNullable<React.ComponentProps<typeof BaseInput>['onChange']>
  >[0];
  type BaseInputBlurEvent = Parameters<
    NonNullable<React.ComponentProps<typeof BaseInput>['onBlur']>
  >[0];
  type BaseInputKeyDownEvent = Parameters<
    NonNullable<React.ComponentProps<typeof BaseInput>['onKeyDown']>
  >[0];
  type BaseInputMouseDownEvent = Parameters<
    NonNullable<React.ComponentProps<typeof BaseInput>['onMouseDown']>
  >[0];

  const initial = toStringValue(value ?? defaultValue ?? '');
  const [inputValue, setInputValue] = React.useState<string>(initial);
  const lastValidRef = React.useRef<string>(
    isValidNumber(initial) ? initial : '',
  );
  const { setIsMiddleButtonDragging } = useInputRootContext();
  const dragActiveRef = React.useRef<boolean>(false);
  const dragStartXRef = React.useRef<number>(0);
  const dragBaseRef = React.useRef<number>(0);
  const dragStepRef = React.useRef<number>(Number(nudgeAmount ?? 1));
  const dragDecimalsRef = React.useRef<number>(0);
  const dragLastStepsRef = React.useRef<number>(0);

  const minNumber = React.useMemo(
    () => (typeof min === 'string' ? Number(min) : min),
    [min],
  );
  const maxNumber = React.useMemo(
    () => (typeof max === 'string' ? Number(max) : max),
    [max],
  );

  React.useEffect(() => {
    if (value !== undefined) {
      const s = toStringValue(value);
      setInputValue(s);
      if (isValidNumber(s)) lastValidRef.current = s;
    }
  }, [value]);

  const handleChange = React.useCallback(
    (e: BaseInputChangeEvent) => {
      const next = e.target.value;
      setInputValue(next);
      if (isValidNumber(next)) {
        lastValidRef.current = next;
      }
      onValueChange?.(next);
      onChange?.(e);
    },
    [onChange, onValueChange],
  );

  // Basic arithmetic expression evaluator: supports + - * / and parentheses, with unary minus
  const numericInputCommit = React.useCallback(() => {
    let next = inputValue;
    const containsOperators = OPERATORS_REGEX.test(inputValue);
    if (containsOperators) {
      const result = evaluateExpression(inputValue);
      if (result !== null) {
        const clamped = clampNumber(result, minNumber, maxNumber);
        next = String(clamped);
      } else if (isValidNumber(lastValidRef.current)) {
        const clamped = clampNumber(
          Number(lastValidRef.current),
          minNumber,
          maxNumber,
        );
        next = String(clamped);
      } else {
        next = lastValidRef.current;
      }
    } else if (!isValidNumber(inputValue)) {
      if (isValidNumber(lastValidRef.current)) {
        const clamped = clampNumber(
          Number(lastValidRef.current),
          minNumber,
          maxNumber,
        );
        next = String(clamped);
      } else {
        next = lastValidRef.current;
      }
    } else {
      const clamped = clampNumber(Number(inputValue), minNumber, maxNumber);
      next = String(clamped);
    }
    setInputValue(next);
    lastValidRef.current = next;
    onValueChange?.(next);
  }, [inputValue, minNumber, maxNumber, onValueChange]);

  const handleBlur = React.useCallback(
    (e: BaseInputBlurEvent) => {
      numericInputCommit();
      onBlur?.(e);
    },
    [numericInputCommit, onBlur],
  );

  const handleKeyDown = React.useCallback(
    (e: BaseInputKeyDownEvent) => {
      if (e.key === 'ArrowUp' || e.key === 'ArrowDown') {
        e.preventDefault();
        const direction = e.key === 'ArrowUp' ? 1 : -1;
        const containsOperators = OPERATORS_REGEX.test(inputValue);
        let base: number | null = null;
        if (containsOperators) base = evaluateExpression(inputValue);
        if (base === null) {
          if (isValidNumber(inputValue)) base = Number(inputValue);
          else if (isValidNumber(lastValidRef.current))
            base = Number(lastValidRef.current);
          else base = 0;
        }
        const step = Number(nudgeAmount ?? 1);
        const decimals = Math.max(
          getDecimalPlaces(base),
          getDecimalPlaces(step),
          typeof minNumber === 'number' ? getDecimalPlaces(minNumber) : 0,
          typeof maxNumber === 'number' ? getDecimalPlaces(maxNumber) : 0,
        );
        const nextNumber = clampNumber(
          base + direction * step,
          minNumber,
          maxNumber,
        );
        const nextString = trimTrailingZeros(nextNumber.toFixed(decimals));
        setInputValue(nextString);
        lastValidRef.current = nextString;
        onValueChange?.(nextString);
      } else if (e.key === 'Enter') {
        numericInputCommit();
        e.currentTarget.blur();
      }
      onKeyDown?.(e);
    },
    [
      inputValue,
      maxNumber,
      minNumber,
      nudgeAmount,
      numericInputCommit,
      onKeyDown,
      onValueChange,
    ],
  );

  const handleMouseDown = React.useCallback(
    (e: BaseInputMouseDownEvent) => {
      if (e.button !== 1) return;
      e.preventDefault();
      const inputEl = (e.currentTarget as unknown as HTMLElement) ?? null;
      const containsOperators = OPERATORS_REGEX.test(inputValue);
      let base: number | null = null;
      if (containsOperators) base = evaluateExpression(inputValue);
      if (base === null) {
        if (isValidNumber(inputValue)) base = Number(inputValue);
        else if (isValidNumber(lastValidRef.current))
          base = Number(lastValidRef.current);
        else base = 0;
      }

      dragActiveRef.current = true;
      setIsMiddleButtonDragging(true);
      dragStartXRef.current = (e as unknown as MouseEvent).clientX;
      dragBaseRef.current = base;
      dragStepRef.current = Number(nudgeAmount ?? 1);
      dragDecimalsRef.current = Math.max(
        getDecimalPlaces(base),
        getDecimalPlaces(dragStepRef.current),
      );
      dragLastStepsRef.current = 0;

      const pixelsPerStep = 8;

      const onMove = (ev: MouseEvent) => {
        if (!dragActiveRef.current) return;
        const dx = ev.clientX - dragStartXRef.current;
        const steps = Math.trunc(dx / pixelsPerStep);
        if (steps === dragLastStepsRef.current) return;
        dragLastStepsRef.current = steps;
        const nextNumber = clampNumber(
          dragBaseRef.current + steps * dragStepRef.current,
          minNumber,
          maxNumber,
        );
        const nextString = trimTrailingZeros(
          nextNumber.toFixed(dragDecimalsRef.current),
        );
        setInputValue(nextString);
        lastValidRef.current = nextString;
        onValueChange?.(nextString);
      };

      const endDrag = () => {
        if (!dragActiveRef.current) return;
        dragActiveRef.current = false;
        setIsMiddleButtonDragging(false);
        window.removeEventListener('mousemove', onMove);
        window.removeEventListener('mouseup', onUp);
        document.body.style.cursor = '';
        if (inputEl) inputEl.style.cursor = '';
      };

      const onUp = () => {
        endDrag();
      };

      window.addEventListener('mousemove', onMove);
      window.addEventListener('mouseup', onUp, { once: true });
      document.body.style.cursor = 'ew-resize';
      if (inputEl) inputEl.style.cursor = 'ew-resize';
    },
    [
      inputValue,
      maxNumber,
      minNumber,
      nudgeAmount,
      onValueChange,
      setIsMiddleButtonDragging,
    ],
  );

  return (
    <TextInputPrimitive
      type='text'
      inputMode='decimal'
      className={className}
      min={min as any}
      max={max as any}
      value={inputValue}
      onChange={handleChange}
      onBlur={handleBlur}
      onKeyDown={handleKeyDown}
      onMouseDown={handleMouseDown}
      {...props}
    />
  );
}

function NumericInput({ className, iconLead, ...props }: NumericInputProps) {
  return (
    <InputRoot className={className}>
      <NumericInputPrimitive iconLead={iconLead} {...props} />
    </InputRoot>
  );
}

export { NumericInput, NumericInputPrimitive };

import React from 'react';
import { cn } from '@/lib/utils';
import chroma from 'chroma-js';
import { TextInputPrimitive } from './text-input';
import { InputRoot, type BaseInputProps } from './input-utils';
import { Input as BaseInput } from '@base-ui/react';

const HEX_RE = /^([0-9a-fA-F]{3}|[0-9a-fA-F]{6}|[0-9a-fA-F]{8})$/;
const HEX8_RE = /^#?[0-9a-fA-F]{8}$/;
const RGBA_RE = /^rgba\(/i;
const HSLA_RE = /^hsla\(/i;
const COLOR_FUNC_RE = /^color\(/i;

const normalizeHex = (s: string): string => {
  const t = s.trim();
  return HEX_RE.test(t) ? `#${t}` : t;
};

const toStringValue = (v: unknown): string => (typeof v === 'string' ? v : '');

const formatHexNoHashUpper = (s: string): string => {
  return chroma(normalizeHex(s)).hex().slice(1).toUpperCase();
};

const hasExplicitAlpha = (s: string): boolean => {
  const t = s.trim();
  return (
    HEX8_RE.test(t) ||
    RGBA_RE.test(t) ||
    HSLA_RE.test(t) ||
    COLOR_FUNC_RE.test(t)
  );
};

const ColorChit = React.memo(function ColorChit({
  color,
  opacity,
  className,
  onClick,
}: {
  color: string;
  opacity?: string | number;
  className?: string;
  onClick?: React.MouseEventHandler<HTMLDivElement>;
}) {
  const swatch = React.useMemo(() => {
    try {
      const norm = normalizeHex(color);
      if (chroma.valid(norm)) return chroma(norm).css();
    } catch {}
    return null;
  }, [color]);

  return (
    <div
      className={cn(
        'inset-ring-black-200 dark:inset-ring-white-200 flex size-4 shrink-0 justify-start overflow-hidden rounded-sm inset-ring',
        onClick && 'cursor-pointer',
        className,
      )}
      style={{
        backgroundImage:
          'conic-gradient(#eee 25%, #ccc 0 50%, #eee 0 75%, #ccc 0)',
        backgroundSize: '8px 8px',
        backgroundPosition: '0 0',
        backgroundRepeat: 'repeat',
      }}
      onClick={onClick}
    >
      <div
        className='h-full w-1/2'
        style={{
          backgroundColor: swatch ?? 'transparent',
        }}
      />
      <div
        className='h-full w-1/2'
        style={{
          backgroundColor: swatch ?? 'transparent',
          opacity: opacity === undefined ? undefined : Number(opacity) / 100,
        }}
      />
    </div>
  );
});

function ColorInputPrimitive({
  onChange,
  onBlur,
  onKeyDown,
  value,
  defaultValue,
  className,
  ...props
}: BaseInputProps) {
  type BaseInputChangeEvent = Parameters<
    NonNullable<React.ComponentProps<typeof BaseInput>['onChange']>
  >[0];
  type BaseInputBlurEvent = Parameters<
    NonNullable<React.ComponentProps<typeof BaseInput>['onBlur']>
  >[0];
  type BaseInputKeyDownEvent = Parameters<
    NonNullable<React.ComponentProps<typeof BaseInput>['onKeyDown']>
  >[0];

  const initial = toStringValue(value ?? defaultValue ?? '');
  const [inputValue, setInputValue] = React.useState<string>(initial);
  const lastValidRef = React.useRef<string>(
    chroma.valid(normalizeHex(initial))
      ? formatHexNoHashUpper(initial)
      : '000000',
  );
  const [opacityPercent, setOpacityPercent] = React.useState<number>(() => {
    try {
      if (chroma.valid(normalizeHex(initial))) {
        const a = chroma(normalizeHex(initial)).alpha();
        return Math.round(a * 100);
      }
    } catch {}
    return 100;
  });

  React.useEffect(() => {
    if (value !== undefined) {
      const s = toStringValue(value);
      setInputValue(s);
      if (chroma.valid(normalizeHex(s))) {
        lastValidRef.current = formatHexNoHashUpper(s);
        if (hasExplicitAlpha(s)) {
          try {
            const a = chroma(normalizeHex(s)).alpha();
            setOpacityPercent(Math.round(a * 100));
          } catch {}
        }
      }
    }
  }, [value]);

  const handleChange = React.useCallback(
    (e: BaseInputChangeEvent) => {
      const next = e.target.value;
      setInputValue(next);
      if (chroma.valid(normalizeHex(next))) {
        lastValidRef.current = formatHexNoHashUpper(next);
        if (hasExplicitAlpha(next)) {
          try {
            const a = chroma(normalizeHex(next)).alpha();
            setOpacityPercent(Math.round(a * 100));
          } catch {}
        }
      }
      onChange?.(e);
    },
    [onChange],
  );

  const commit = React.useCallback(() => {
    if (chroma.valid(normalizeHex(inputValue))) {
      const hexNoHashUpper = formatHexNoHashUpper(inputValue);
      setInputValue(hexNoHashUpper);
      lastValidRef.current = hexNoHashUpper;
      if (hasExplicitAlpha(inputValue)) {
        try {
          const a = chroma(normalizeHex(inputValue)).alpha();
          setOpacityPercent(Math.round(a * 100));
        } catch {}
      }
    } else {
      setInputValue(lastValidRef.current);
    }
  }, [inputValue]);

  const handleBlur = React.useCallback(
    (e: BaseInputBlurEvent) => {
      commit();
      onBlur?.(e);
    },
    [commit, onBlur],
  );

  const handleKeyDown = React.useCallback(
    (e: BaseInputKeyDownEvent) => {
      if (e.key === 'Enter') {
        commit();
        e.currentTarget.blur();
      }
      onKeyDown?.(e);
    },
    [commit, onKeyDown],
  );

  const previewHex = lastValidRef.current;
  const previewColor = React.useMemo(() => {
    try {
      return chroma(`#${previewHex}`)
        .alpha((opacityPercent ?? 100) / 100)
        .css();
    } catch {
      return `#${previewHex}`;
    }
  }, [previewHex, opacityPercent]);

  return (
    <TextInputPrimitive
      type='text'
      {...props}
      value={inputValue}
      onChange={handleChange}
      onBlur={handleBlur}
      onKeyDown={handleKeyDown}
      className={cn('w-full flex-1 outline-none', className)}
    />
  );
}

function ColorInput({
  className,
  ...props
}: React.ComponentProps<typeof BaseInput>) {
  return (
    <InputRoot className={cn(className)}>
      <ColorInputPrimitive {...props} />
    </InputRoot>
  );
}

export { ColorInput, ColorChit, ColorInputPrimitive };

'use client';

import { cn } from '@/lib/utils';
import { Input as BaseInput } from '@base-ui/react';
import { createContext, useContext, useState } from 'react';

// types
interface BaseInputProps extends React.ComponentProps<typeof BaseInput> {
  iconLead?: React.ReactNode;
  iconTrail?: React.ReactNode;
}

type InputRootContextType = {
  isMiddleButtonDragging: boolean;
  setIsMiddleButtonDragging: (isMiddleButtonDragging: boolean) => void;
};

// context
const InputRootContext = createContext<InputRootContextType>({
  isMiddleButtonDragging: false,
  setIsMiddleButtonDragging: () => {},
});

// component
function InputRoot({ className, children }: BaseInputProps) {
  const [isMiddleButtonDragging, setIsMiddleButtonDragging] = useState(false);

  return (
    <InputRootContext.Provider
      value={{
        isMiddleButtonDragging,
        setIsMiddleButtonDragging,
      }}
    >
      <div
        className={cn(
          'placeholder:text-grey-400 text-black-800 bg-grey-100 typography-body-medium hover:ring-grey-200 dark:placeholder:text-grey-400 dark:bg-grey-700 dark:text-white-1000 dark:hover:ring-grey-600 flex h-6 w-full min-w-0 items-center rounded-md ring ring-transparent outline-none selection:bg-blue-500 focus-within:ring-blue-500 hover:focus-within:ring-blue-500 disabled:pointer-events-none disabled:cursor-not-allowed disabled:opacity-50 aria-invalid:border-red-500 aria-invalid:ring-red-500/20 dark:focus-within:ring-blue-500',
          isMiddleButtonDragging &&
            'cursor-ew-resize !ring-blue-600 dark:!ring-blue-400',
          className,
        )}
      >
        {children}
      </div>
    </InputRootContext.Provider>
  );
}

function InputMultiRoot({
  children,
  className,
}: {
  children: React.ReactNode;
  className?: string;
}) {
  return (
    <InputRoot
      className={cn(
        'divide-white-1000 dark:divide-grey-800 flex divide-x [&>*:not(:last-child)]:pr-1',
        className,
      )}
    >
      {children}
    </InputRoot>
  );
}

// hook
function useInputRootContext(): InputRootContextType {
  return useContext(InputRootContext);
}

export { InputRoot, InputMultiRoot, type BaseInputProps, useInputRootContext };
